INSERT INTO scenario_template_version (
    id, template_id, version_label, scenario_schema_version, definition_jsonb, is_default
)
VALUES (
    #{versionId}, #{templateId}, #{versionLabel}, #{schemaVersion}, CAST(#{definitionJsonb} AS jsonb), #{isDefault}
)
ON CONFLICT (template_id, version_label) DO UPDATE SET
    scenario_schema_version = EXCLUDED.scenario_schema_version,
    definition_jsonb = EXCLUDED.definition_jsonb,
    is_default = EXCLUDED.is_default
